// Mock Data
let properties = [
    {
      id: 1,
      title: "Beautiful Land in Downtown",
      type: "land",
      location: "123 Main Street, New York",
      area: 500,
      price: 250000,
      status: "available",
      description: "Prime location land perfect for residential development. Close to all amenities including schools, hospitals, and shopping centers.",
      sellerId: 1,
      createdAt: "2024-01-15"
    },
    {
      id: 2,
      title: "Commercial Plot",
      type: "commercial",
      location: "456 Business Ave, Los Angeles",
      area: 1000,
      price: 500000,
      status: "available",
      description: "Excellent commercial property in high-traffic area. Ideal for retail or office space development.",
      sellerId: 2,
      createdAt: "2024-01-20"
    },
    {
      id: 3,
      title: "Residential Land",
      type: "land",
      location: "789 Suburb Lane, Chicago",
      area: 300,
      price: 150000,
      status: "sold",
      description: "Quiet residential area with great neighborhood. Perfect for building your dream home.",
      sellerId: 1,
      createdAt: "2024-02-01"
    },
    {
      id: 4,
      title: "Luxury Estate Plot",
      type: "land",
      location: "101 Elite Road, Miami",
      area: 2000,
      price: 1500000,
      status: "available",
      description: "Exclusive luxury estate land with ocean views. Gated community with 24/7 security.",
      sellerId: 3,
      createdAt: "2024-02-10"
    },
    {
      id: 5,
      title: "Industrial Zone Land",
      type: "commercial",
      location: "202 Factory Street, Detroit",
      area: 5000,
      price: 750000,
      status: "pending",
      description: "Large industrial land suitable for manufacturing or warehouse facilities.",
      sellerId: 2,
      createdAt: "2024-02-15"
    }
  ];

  let sellers = [
    {
      id: 1,
      name: "John Smith",
      email: "john.smith@email.com",
      phone: "+1 234-567-8901",
      company: "Smith Real Estate",
      address: "100 Realty Blvd, New York",
      createdAt: "2024-01-01"
    },
    {
      id: 2,
      name: "Sarah Johnson",
      email: "sarah.j@email.com",
      phone: "+1 234-567-8902",
      company: "Johnson Properties",
      address: "200 Property Lane, Los Angeles",
      createdAt: "2024-01-05"
    },
    {
      id: 3,
      name: "Michael Brown",
      email: "m.brown@email.com",
      phone: "+1 234-567-8903",
      company: "Brown & Associates",
      address: "300 Estate Ave, Miami",
      createdAt: "2024-01-10"
    }
  ];

  let users = [
    {
      id: 1,
      name: "Admin User",
      email: "admin@example.com",
      password: "admin123",
      role: "admin"
    },
    {
      id: 2,
      name: "Regular User",
      email: "user@example.com",
      password: "user123",
      role: "user"
    }
  ];

  // Simulate API delay
  const delay = (ms) => new Promise(resolve => setTimeout(resolve, ms));

  // Auth API
  export const authAPI = {
    login: async (email, password) => {
      await delay(500);
      const user = users.find(u => u.email === email && u.password === password);
      if (user) {
        const { password, ...userWithoutPassword } = user;
        return { success: true, user: userWithoutPassword, token: 'mock-jwt-token' };
      }
      throw new Error('Invalid email or password');
    },

    register: async (userData) => {
      await delay(500);
      const exists = users.find(u => u.email === userData.email);
      if (exists) {
        throw new Error('Email already exists');
      }
      const newUser = {
        id: users.length + 1,
        ...userData,
        role: 'user'
      };
      users.push(newUser);
      const { password, ...userWithoutPassword } = newUser;
      return { success: true, user: userWithoutPassword };
    }
  };

  // Properties API
  export const propertiesAPI = {
    getAll: async () => {
      await delay(300);
      return properties.map(p => ({
        ...p,
        seller: sellers.find(s => s.id === p.sellerId)
      }));
    },

    getById: async (id) => {
      await delay(300);
      const property = properties.find(p => p.id === parseInt(id));
      if (property) {
        return {
          ...property,
          seller: sellers.find(s => s.id === property.sellerId)
        };
      }
      throw new Error('Property not found');
    },

    create: async (propertyData) => {
      await delay(300);
      const newProperty = {
        id: properties.length + 1,
        ...propertyData,
        createdAt: new Date().toISOString().split('T')[0]
      };
      properties.push(newProperty);
      return newProperty;
    },

    update: async (id, propertyData) => {
      await delay(300);
      const index = properties.findIndex(p => p.id === parseInt(id));
      if (index !== -1) {
        properties[index] = { ...properties[index], ...propertyData };
        return properties[index];
      }
      throw new Error('Property not found');
    },

    delete: async (id) => {
      await delay(300);
      const index = properties.findIndex(p => p.id === parseInt(id));
      if (index !== -1) {
        properties.splice(index, 1);
        return { success: true };
      }
      throw new Error('Property not found');
    },

    search: async (filters) => {
      await delay(300);
      let result = [...properties];

      if (filters.keyword) {
        const keyword = filters.keyword.toLowerCase();
        result = result.filter(p => 
          p.title.toLowerCase().includes(keyword) ||
          p.location.toLowerCase().includes(keyword)
        );
      }

      if (filters.type && filters.type !== 'all') {
        result = result.filter(p => p.type === filters.type);
      }

      if (filters.status && filters.status !== 'all') {
        result = result.filter(p => p.status === filters.status);
      }

      if (filters.minPrice) {
        result = result.filter(p => p.price >= parseInt(filters.minPrice));
      }

      if (filters.maxPrice) {
        result = result.filter(p => p.price <= parseInt(filters.maxPrice));
      }

      return result.map(p => ({
        ...p,
        seller: sellers.find(s => s.id === p.sellerId)
      }));
    }
  };

  // Sellers API
  export const sellersAPI = {
    getAll: async () => {
      await delay(300);
      return sellers;
    },

    getById: async (id) => {
      await delay(300);
      const seller = sellers.find(s => s.id === parseInt(id));
      if (seller) {
        return seller;
      }
      throw new Error('Seller not found');
    },

    create: async (sellerData) => {
      await delay(300);
      const newSeller = {
        id: sellers.length + 1,
        ...sellerData,
        createdAt: new Date().toISOString().split('T')[0]
      };
      sellers.push(newSeller);
      return newSeller;
    },

    update: async (id, sellerData) => {
      await delay(300);
      const index = sellers.findIndex(s => s.id === parseInt(id));
      if (index !== -1) {
        sellers[index] = { ...sellers[index], ...sellerData };
        return sellers[index];
      }
      throw new Error('Seller not found');
    },

    delete: async (id) => {
      await delay(300);
      const index = sellers.findIndex(s => s.id === parseInt(id));
      if (index !== -1) {
        sellers.splice(index, 1);
        return { success: true };
      }
      throw new Error('Seller not found');
    }
  };

  // Statistics API
  export const statsAPI = {
    getDashboardStats: async () => {
      await delay(300);
      return {
        totalProperties: properties.length,
        availableProperties: properties.filter(p => p.status === 'available').length,
        totalSellers: sellers.length,
        totalValue: properties.reduce((sum, p) => sum + p.price, 0)
      };
    }
  };
